// Map incoming payload to the config set-config webhook format.
// Expected input:
//   { key, value, environment, trading_mode, author, reason }
// value may be a string, number, boolean, or object with type hint:
//   { string_val } | { bool_val } | { int_val } | { float_val } | { json_val }
const body = $input.item.json.body || $input.item.json;

if (!body.key) throw new Error('Missing required field: key');
if (body.value === undefined) throw new Error('Missing required field: value');

const payload = {
  key: body.key,
  value: body.value,
  environment: body.environment || 'DEV',
  trading_mode: body.trading_mode || 'ALL',
  author: body.author || 'n8n',
  reason: body.reason || 'n8n config update workflow',
};

return { json: payload };
